mapper.select:
SELECT * FROM agent_context_artifact
WHERE artifact_id = #{artifactId} AND root_run_id = #{rootRunId}
LIMIT 1

SELECT * FROM agent_context_artifact
WHERE root_run_id = #{rootRunId}
ORDER BY create_time ASC, id ASC

SELECT * FROM agent_context_artifact
WHERE root_run_id = #{rootRunId}
  AND (artifact_id LIKE '%' || #{query} || '%' OR preview LIKE '%' || #{query} || '%')
ORDER BY create_time ASC, id ASC
LIMIT #{limit}

SELECT * FROM agent_context_artifact
WHERE conversation_id = #{conversationId}
ORDER BY create_time ASC
